// Colourspace boundary for the image-carrier deblur smoke: PNG/JPEG bytes in,
// single-channel luminance plane out as Float32 in [0, 1] (row-major).
// Assumption: sRGB greyscale, gamma left as-is. Linear-light promotion is
// deferred — as long as blur and recovery both traverse the same gamma curve,
// PSNR comparisons inside the smoke remain valid.
// `sharp` is dynamically imported so importing other parts of this package
// from non-Node environments does not eagerly pull the native binding.

export interface DecodedLuminance {
  plane: Float32Array;
  width: number;
  height: number;
}

/**
 * Handles the gnosis decode Luminance workflow.
 */
export async function decodeLuminance(input: string | Buffer): Promise<DecodedLuminance> {
  const sharp = (await import('sharp')).default;
  const { data, info } = await sharp(input)
    .removeAlpha()
    .toColourspace('srgb')
    .greyscale()
    .raw()
    .toBuffer({ resolveWithObject: true });

  if (info.channels !== 1) {
    throw new Error(
      `decodeLuminance: expected 1 channel after greyscale(), got ${info.channels}`,
    );
  }

  const { width, height } = info;
  const plane = new Float32Array(width * height);
  for (let i = 0; i < plane.length; i++) {
    plane[i] = data[i] / 255;
  }

  return { plane, width, height };
}
